'use strict';

const fs = require('fs');
const path = require('path');

const OPENCLAW_WORKER_SHIM_MARKER =
  'Generated by LobsterAI. Bridges gateway-bundle.mjs worker resolution to dist/agents.';

const OPENCLAW_WORKER_SHIM_TARGETS = [
  {
    shimFile: 'model-provider-auth.worker.mjs',
    targetFile: path.join('dist', 'agents', 'model-provider-auth.worker.js'),
  },
  {
    shimFile: 'code-mode.worker.mjs',
    targetFile: path.join('dist', 'agents', 'code-mode.worker.js'),
  },
  {
    shimFile: 'compaction-planning.worker.mjs',
    targetFile: path.join('dist', 'agents', 'compaction-planning.worker.js'),
  },
];

function toImportPath(filePath) {
  return filePath.split(path.sep).join('/');
}

function buildOpenClawWorkerShimContent(targetFile) {
  return [
    `// ${OPENCLAW_WORKER_SHIM_MARKER}`,
    `import './${toImportPath(targetFile)}';`,
    '',
  ].join('\n');
}

function isGeneratedOpenClawWorkerShim(content) {
  return content.includes(OPENCLAW_WORKER_SHIM_MARKER);
}

function ensureOpenClawWorkerShims(runtimeRoot) {
  const result = {
    created: [],
    updated: [],
    unchanged: [],
    missingTargets: [],
    protectedExisting: [],
    skippedBecauseBundleMissing: false,
  };

  if (!fs.existsSync(path.join(runtimeRoot, 'gateway-bundle.mjs'))) {
    result.skippedBecauseBundleMissing = true;
    return result;
  }

  for (const target of OPENCLAW_WORKER_SHIM_TARGETS) {
    const targetPath = path.join(runtimeRoot, target.targetFile);
    const shimPath = path.join(runtimeRoot, target.shimFile);
    if (!fs.existsSync(targetPath)) {
      result.missingTargets.push(target.shimFile);
      continue;
    }

    const expectedContent = buildOpenClawWorkerShimContent(target.targetFile);
    if (fs.existsSync(shimPath)) {
      const existing = fs.readFileSync(shimPath, 'utf8');
      if (existing === expectedContent) {
        result.unchanged.push(target.shimFile);
        continue;
      }
      if (!isGeneratedOpenClawWorkerShim(existing)) {
        result.protectedExisting.push(target.shimFile);
        continue;
      }
      fs.writeFileSync(shimPath, expectedContent, 'utf8');
      result.updated.push(target.shimFile);
      continue;
    }

    fs.writeFileSync(shimPath, expectedContent, 'utf8');
    result.created.push(target.shimFile);
  }

  return result;
}

module.exports = {
  OPENCLAW_WORKER_SHIM_MARKER,
  OPENCLAW_WORKER_SHIM_TARGETS,
  buildOpenClawWorkerShimContent,
  ensureOpenClawWorkerShims,
  isGeneratedOpenClawWorkerShim,
};
